#!/usr/bin/env node
/**
 * VEXTREME — lib/run-test-prereqs.js
 *
 * Runs the build scripts tests/helpers/prereqs.js declares as required
 * before the test suite can read generated files (pages/archives.html,
 * etc.). Replaces a hardcoded `run:` line in .github/workflows/test.yml —
 * that line and this list could previously drift; now there is one array
 * to update when a test file gains a new prerequisite.
 *
 * Run manually:   node lib/run-test-prereqs.js
 * Auto-run via:   .github/workflows/test.yml "Build test prerequisites" step
 *
 * LATTICE:BEGIN — generated by lib/build-lattice-headers.js from docs/lattice-map.json. Do not hand-edit; edit the JSON and regenerate.
 *   role      : runs the build scripts tests/helpers/prereqs.js declares as required before the test suite can read generated files — replaces a hardcoded run: line in .github/workflows/test.yml
 *   reads     : tests/helpers/prereqs.js (PREREQUISITE_SCRIPTS)
 *   writes    : whatever each script in PREREQUISITE_SCRIPTS writes (currently data/strings/compiled∕*, pages/archives.html) — this file only orchestrates, it has no output of its own
 *   loaded-by : .github/workflows/test.yml ('Build test prerequisites' step)
 *   tested-by : (none)
 *
 *   CHANGE MAP — if you touch X here, also check:
 *     a test file gains a new build-time prerequisite:
 *       - tests/helpers/prereqs.js's PREREQUISITE_SCRIPTS array — add it there, not to this file or the workflow directly
 *       - the new test file's own PREREQUISITE docstring — reference tests/helpers/prereqs.js rather than re-listing the scripts inline, so the two can't drift again
 * LATTICE:END
 */

'use strict';

const path = require('path');
const { execFileSync } = require('child_process');
const { PREREQUISITE_SCRIPTS } = require('../tests/helpers/prereqs');

const ROOT = path.join(__dirname, '..');

for (const script of PREREQUISITE_SCRIPTS) {
  console.log(`[run-test-prereqs] node ${script}`);
  execFileSync(process.execPath, [path.join(ROOT, script)], {
    cwd: ROOT,
    stdio: 'inherit',
  });
}

console.log(`[run-test-prereqs] Done. Ran ${PREREQUISITE_SCRIPTS.length} script(s).`);

// [VXG RealForever]
